New-Item -ItemType Directory -Force $rawDir, $chatDir | Out-Null

if (-not (Test-Path $projectsDir)) { exit 0 }

foreach ($f in Get-ChildItem $projectsDir -Recurse -Filter *.jsonl -File) {
