          $texts += "*[Thao tac file: $($p.name) -> $($p.input.file_path)]*"
        }
      }
    }
    $text = ($texts -join "`n").Trim()
    if (-not $text) { continue }

    # Luoc bo chuoi base64 dai de file nhe va doc duoc
    $text = $text -replace '[A-Za-z0-9+/=]{500,}', '[CHUOI BASE64 DA LUOC BO]'
    if ($text.Length -gt 30000) { $text = $text.Substring(0, 30000) + "`n... [da cat bot phan qua dai]" }

    if ($j.type -eq 'user') {
      if (-not $title) { $title = ($text -replace '\s+', ' ').Substring(0, [Math]::Min(80, $text.Length)) }
      $role = '## Nguoi dung'
    } else { $role = '## Claude' }
    $body.Add(''); $body.Add('---'); $body.Add(''); $body.Add($role); $body.Add(''); $body.Add($text)
  }

  $out.Add("# $title")
  $out.Add('')
  $out.Add("- Phien: $($f.BaseName)")
  $out.Add("- Project: $proj")
  $out.Add("- Cap nhat: $(Get-Date -Format 'yyyy-MM-dd HH:mm')")
  if ($files.Count -gt 0) {
    $out.Add('')
    $out.Add('## File da tao / sua trong phien nay')
    foreach ($fp in $files) { $out.Add("- $fp") }
  }
  $out.AddRange($body)
  [IO.File]::WriteAllLines($md, $out, (New-Object Text.UTF8Encoding($true)))
}

