  foreach ($line in [IO.File]::ReadLines($f.FullName, [Text.Encoding]::UTF8)) {
    try { $j = $line | ConvertFrom-Json } catch { continue }
    if ($j.type -ne 'user' -and $j.type -ne 'assistant') { continue }
